INSERT INTO public."Product" VALUES ('7488a27d-5169-4d51-808b-7b90717a1dde', 'dhb-0158', 'ماي واي', 'Giorgio Armani My Way', 'DHB-0158', 'عطر نسائي عصري ومشرق يفتتح بنضارة البرغموت وزهر البرتقال مع قلب أنثوي فواح من مسك الروم والياسمين وقاعدة دافئة من الفانيلا والمسك الأبيض.', NULL, '4508d8b5-67dd-4c8d-bb58-c4fc3cc706bc', NULL, '942226c3-cf6b-4a56-9584-f65a066f3d07', 'ced7dc31-11ac-4235-aa30-798281d523c3', '86883e85-42e6-436c-a73d-50247baf4fdc', true, false, 0, '2026-07-12 14:30:23.641', '2026-07-12 18:56:10.241', false, NULL, 'UNVERIFIED', 'DIRECT_LIQUID', 'MISSING');
INSERT INTO public."Product" VALUES ('81c54216-e514-495e-b900-82f324bc72d4', 'dhb-0181', 'انفكتوس', 'Paco Rabanne Invictus', 'DHB-0181', 'عطر رجالي منعش ومفعم بالحيوية يجسد القوة بمزيج من النوتات البحرية الباردة وقشر الجريب فروت مع قاعدة خشبية دافئة من العنبر.', NULL, 'd4d0ad4a-9a6d-4235-97ce-eaebda3e5555', NULL, '7c00964d-cae9-41fc-ada2-c58b2ecf3f85', 'ced7dc31-11ac-4235-aa30-798281d523c3', '61bac8c5-cca0-42c7-b875-ce15804bcbee', true, false, 0, '2026-07-12 14:30:25.267', '2026-07-12 18:56:13.358', false, NULL, 'UNVERIFIED', 'DIRECT_LIQUID', 'MISSING');
INSERT INTO public."Product" VALUES ('d3581500-7609-4572-aaae-6ab94c6c031a', 'dhb-0183', 'انفكتوس ليجند', 'Paco Rabanne Invictus Legend', 'DHB-0183', 'عطر رجالي مائي حار يتميز بنفحات ملح البحر وجوز الهند المنعشة مع حرارة التوابل وقاعدة خشبية دافئة وثابتة من العنبر الأحمر.', NULL, 'd4d0ad4a-9a6d-4235-97ce-eaebda3e5555', NULL, '7c00964d-cae9-41fc-ada2-c58b2ecf3f85', 'ced7dc31-11ac-4235-aa30-798281d523c3', '16036891-c84e-4d38-ba42-d84654b98b7a', true, false, 0, '2026-07-12 14:30:25.388', '2026-07-12 18:56:13.618', false, NULL, 'UNVERIFIED', 'DIRECT_LIQUID', 'MISSING');
INSERT INTO public."Product" VALUES ('538bc5ab-e448-4ca0-aa75-aee8a7571138', 'dhb-0196', 'اونلي ذا بريڤ', 'Diesel Only The Brave', 'DHB-0196', 'عطر رجالي قوي وجريء يفتتح بانتعاش الليمون والماندرين وقلب من أوراق البنفسج وقاعدة دافئة وثابتة من الجلود والعنبر وخشب الأرز.', NULL, 'd4d0ad4a-9a6d-4235-97ce-eaebda3e5555', NULL, '7c00964d-cae9-41fc-ada2-c58b2ecf3f85', 'ced7dc31-11ac-4235-aa30-798281d523c3', '8ac7219f-237e-44e2-a7b5-226450f1239c', true, false, 0, '2026-07-12 14:30:26.298', '2026-07-12 18:56:15.241', false, NULL, 'UNVERIFIED', 'DIRECT_LIQUID', 'MISSING');
